# Skeptic packet solve S50-T1-A-E2: three-route assess for contract gate
def assess(record: dict) -> str:
    required = {'slices', 'case_id', 'tasks', 'holdout', 'rubric_levels'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if (not (sum(record["slices"].values()) != record["tasks"] or record["holdout"] == 0)) else 'REBUILD_EVAL_DATASET'

valid = {'case_id': 'CASO-ICA-050-1A', 'tasks': 40, 'slices': {'normal': 25, 'edge': 10, 'adversarial': 5}, 'rubric_levels': {0, 1, 2, 3}, 'holdout': 10}
invalid = {'case_id': 'CASO-ICA-050-1A', 'tasks': 1040, 'slices': {'normal': 25, 'edge': 10, 'adversarial': 5}, 'rubric_levels': {0, 1, 2, 3}, 'holdout': 10}
incomplete = {**valid}
incomplete.pop('holdout', None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)
assert results[0] == 'PASS' and results[2].startswith('MISSING'), results

